<template >
    <div id = "app" >
        <auth v-if = "state === 'login'"
              @resetPass = "state = 'reset_pass'"
              @authorized = "state = 'authorized'" ></auth >
        <resetPass v-if = "state === 'reset_pass'"
                   @auth = "state = 'login'" ></resetPass >
        <mainpage v-if = "state === 'authorized'" ></mainpage>
        <notes v-if = "state === 'authorized'" ></notes >
    </div >
</template >

<script >
  import auth from "./components/auth";
  import reset_pass from "./components/reset_pass";
  import notifications from "./components/notifications";
  import main from "./views/main";

  export default {
    name: "index",
    data() {
      return {
        state: "login",
      };
    },
    components: {
      auth: auth,
      resetPass: reset_pass,
      notes: notifications,
      mainpage: main
    },
  };
</script >

<style >
    @import url('https://fonts.googleapis.com/css2?family=PT+Sans:ital,wght@0,400;0,700;1,400;1,700&display=swap');
    @import "includes/styles/_reset.css";
    @import 'includes/styles/_typo.css';
    @import 'includes/styles/_template.css';
    @import 'includes/styles/_style.css';
    @import 'includes/styles/_sprites.css';
</style >
